targets.expr:
time() - 
  kube_pod_created{cluster=~"$cluster",pod=~"$pod", namespace=~"$namespace"} 
  * on (pod, namespace) group_right(container) 
  kube_pod_container_info{cluster=~"$cluster",
    pod=~"$pod", 
    namespace=~"$namespace", 
    container=~"$container"
  }

sum by(source) (
  count_over_time(
    {source="fluent_bit", job="kube_events", cluster=~"$cluster"} 
    | json
    | type="Normal"
    | metadata_namespace=~"$namespace"
    [$__range]
  ) > 0
)

sum by (type) (count_over_time(
  {source="fluent_bit", job="kube_events", cluster=~"$cluster"}
  | json
  | metadata_namespace=~`$namespace` 
[5m]
))

{source="fluent_bit", job="kube_events", cluster=~"$cluster"} 
  | json  
  | metadata_namespace=~`$namespace` 
  | line_format `{{if eq .type "Normal"}}✅{{else}}⚠️{{end}} {{.type}} | 📦 Object: {{.involvedObject_kind}}/{{.involvedObject_name}} ({{.involvedObject_namespace}}) -> {{.reason}} 
🛠️ Source: {{.source_component}} {{if ne .source_host ""}}🌐 Host: {{.source_host}} {{end}}
📝 Message: {{.message | trim}}`

sum by (kubernetes_namespace_name) (count_over_time(
  {source="fluent_bit", job="kube_logs", cluster=~"$cluster"}
  | json
  | __error__=""
[$__range]
))

sum by (detected_level) (
  count_over_time(
    {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"} 
      | json 
      | __error__=""
      | detected_level = "info" [$__range]
  )
)

sum by (detected_level) (
  count_over_time(
    {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"} 
      | json 
      | __error__=""
      | detected_level = "unknown" [$__range]
  )
)

sum by (detected_level) (
  count_over_time(
    {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"} 
      | json 
      | __error__=""
      | detected_level = "warn" [$__range]
  )
)

sum by (detected_level) (
  count_over_time(
    {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"} 
      | json 
      | __error__=""
      | detected_level = "error" [$__range]
  )
)

sum by (detected_level) (
  count_over_time(
    {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"} 
      | json 
      | __error__=""
      | detected_level = "debug" [$__range]
  )
)

sum by (detected_level) (
  count_over_time(
    {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"} 
      | json 
      | __error__=""
      | detected_level = "critical" [$__range]
  )
)

sum by (detected_level) (count_over_time(
  {source="fluent_bit", job="kube_logs", cluster=~"$cluster", kubernetes_namespace_name=~"$namespace", kubernetes_container_name=~"$container", kubernetes_pod_name=~"$pod"}
  | json
  | detected_level != ""
[5m]
))
